ALTER TABLE model_stats ADD COLUMN losses_by_role JSON DEFAULT NULL;
ALTER TABLE dual_reports ADD COLUMN archived_at DATETIME NULL DEFAULT NULL;

import { ReportPayload } from '../types/reportTypes';

export const auditTextQuality = (payload: ReportPayload): boolean => {
  const text = JSON.stringify(payload);
  // Check for mojibake (common replacement characters)
  const mojibakeRegex = /[\uFFFD\u001A\u0000-\u001F\u007F-\u009F]/g;
  if (mojibakeRegex.test(text)) {
    return false;
  }
  // Additional checks for control characters or unexpected patterns
  return true;
};

