     public function getModelStats($modelId) {
         $stats = $this->db->query("SELECT * FROM model_stats WHERE model_id = ?", [$modelId]);
         return $stats->fetch();
     }

+    public function updateDualModeStandings($modelId, $role, $isWin) {
+        $column = $isWin ? 'wins_by_role' : 'losses_by_role';
+        $this->db->execute("UPDATE model_stats SET {$column} = JSON_SET(COALESCE({$column}, '{}'), '$.{$role}', COALESCE(JSON_UNQUOTE(JSON_EXTRACT({$column}, '$.{$role}')), 0) + 1) WHERE model_id = ?", [$modelId]);
+    }
 }

